[SRSReportParameterAttribute(classStr(ETGCashewshipmentContract))]
class ETGCashewShipmetDataProvider extends  SRSReportDataProviderPreProcessTempDB

{
    ETGCashewShipmentTmp                    ETGCashewShipmentTmp;
    TransDate                               _fromDate,_ToDate;
    List                                    _InvoiceId= new List(Types::String);
    List                                    _CustAccount= new List(Types::String);
    CustInvoiceJour                         _CustInvoiceJour;
    CustInvoiceTrans                        _CustInvoiceTrans;
    ETGSalesShipmentCashew                  _ETGSalesShipmentCashew;

}

